#include<bits/stdc++.h>
using namespace std;
int n,m,ans,f[50010][41],cnt[50010][41];
int main()
{
    scanf("%d%d",&n,&m);
    for(int i=1;i<=m;i++)
    {
        int a,b,c;
        scanf("%d%d%d",&a,&b,&c);
        int e=0,f=0;
        for(int j=1;j<=b;j++)
        {
            int x;
            scanf("%d",&x);
            x=((x-a)%n+n)%n;
            e|=(1<<x);
        }
        for(int j=1;j<=c;j++)
        {
            int x;
            scanf("%d",&x);
            x=((x-a)%n+n)%n;
            f|=(1<<x);
        }
        for(int j=0;j<32;j++)
        {
            if((j&e)||((~j)&f))
            {
                cnt[a][j]++;
            }
        }
    }
    int ans=0;
    for(int i=0;i<32;i++)
    {
        memset(f[0],128,sizeof(f[0]));
        f[0][i]=0;
        for(int j=1;j<=n;j++)
        {
            for(int k=0;k<32;k++)
            {
                f[j][k]=max(f[j-1][(k&15)<<1],f[j-1][(k&15)<<1|1])+cnt[j][k];
            }
        }
        ans=max(ans,f[n][i]);
    }
    printf("%d\n",ans);
    return 0;
}
